app.post("/insert-notification", website_upload.single('notification_file'), (req, res) => {
  const { title, type, description, start_date, end_date, session_id, campus_id, created_by, is_active } = req.body;
  const notification_file = req.file ? `notifications/${req.file.filename}` : null;

  const query = `
    INSERT INTO notifications 
    (title, type, description, start_date, end_date, session_id, campus_id, created_by, notification_file, is_active, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())
  `;

  connection.getConnection((err, conn) => {
    if (err) return res.status(500).json({ error: "DB connection error" });
    conn.query(query, [title, type, description, start_date, end_date || null, session_id, campus_id, created_by, notification_file, is_active || 1], (error, result) => {
      conn.release();
      if (error) { console.error(error); return res.status(500).json({ error: "Insert failed" }); }
      res.json({ success: true, message: "Notification added successfully", id: result.insertId });
    });
  });
});

