app.put("/update-notification/:id", (req, res) => {
  website_upload.single('notification_file')(req, res, (err) => {
    if (err) {
      console.error("Multer Error:", err.message);
      return res.status(400).json({ error: err.message });
    }

    const { id } = req.params;
    const { title, type, description, start_date, end_date, session_id, campus_id, is_active, current_file } = req.body;
    const notification_file = req.file ? `notifications/${req.file.filename}` : current_file;

    const query = `
      UPDATE notifications SET
        title = ?, type = ?, description = ?, start_date = ?, end_date = ?,
        session_id = ?, campus_id = ?, notification_file = ?, is_active = ?, updated_at = NOW()
      WHERE id = ?
    `;

    connection.getConnection((err, conn) => {
      if (err) return res.status(500).json({ error: "DB connection error" });
      conn.query(query, [title, type, description, start_date, end_date || null, session_id, campus_id, notification_file, is_active, id], (error) => {
        conn.release();
        if (error) { console.error(error); return res.status(500).json({ error: "Update failed" }); }
        res.json({ success: true, message: "Notification updated successfully" });
      });
    });
  });
});

