app.get("/get-notification/:id/:campus_id", (req, res) => {
  const { id, campus_id } = req.params;
  const query = `SELECT * FROM notifications WHERE id = ? AND campus_id = ?`;

  connection.getConnection((err, conn) => {
    if (err) return res.status(500).json({ error: "DB connection error" });
    conn.query(query, [id, campus_id], (error, results) => {
      conn.release();
      if (error) { console.error(error); return res.status(500).json({ error: "Fetch failed" }); }
      res.json({ results });
    });
  });
});



