app.get("/notification-detail/:id", (req, res) => {
  const { id } = req.params;
  if (!id || isNaN(id) || parseInt(id) <= 0)
    return res.status(400).json({ error: "Invalid notification ID" });

  connection.getConnection((err, conn) => {
    if (err) return res.status(500).json({ error: "DB connection failed" });
    conn.query("SELECT * FROM notifications WHERE id = ?", [parseInt(id)], (error, results) => {
      conn.release();
      if (error) return res.status(500).json({ error: "Query failed" });
      if (!results.length) return res.status(404).json({ error: "Not found" });
      return res.status(200).json(results[0]);
    });
  });
});

app.get("/notification-list", (req, res) => {
  const { campus_id, session_id, type, search, page = 1, limit = 10 } = req.query;

  if (!campus_id) {
    return res.status(400).json({ error: "campus_id is required" });
  }

  const pageNum   = parseInt(page);
  const limitNum  = parseInt(limit);
  const offset    = (pageNum - 1) * limitNum;

  // Base filter
  let whereClause = `WHERE campus_id = ? AND is_active = 1`;
  const params    = [campus_id];

  // ✅ Type filter (News / Event / Notification)
  if (type) {
    whereClause += ` AND type = ?`;
    params.push(type);
  }

  // Search filter
  if (search) {
    whereClause += ` AND (title LIKE ? OR type LIKE ? OR description LIKE ?)`;
    params.push(`%${search}%`, `%${search}%`, `%${search}%`);
  }

  const countQuery = `SELECT COUNT(*) AS total FROM notifications ${whereClause}`;
  const dataQuery  = `SELECT * FROM notifications ${whereClause} ORDER BY created_at DESC LIMIT ? OFFSET ?`;

  connection.getConnection((err, conn) => {
    if (err) {
      console.error("Connection error:", err);
      return res.status(500).json({ error: "DB connection error" });
    }

    conn.query(countQuery, params, (countErr, countResult) => {
      if (countErr) {
        conn.release();
        console.error("Count error:", countErr);
        return res.status(500).json({ error: "Count query failed" });
      }

      const total      = countResult[0].total;
      const totalPages = Math.ceil(total / limitNum);

      conn.query(dataQuery, [...params, limitNum, offset], (dataErr, results) => {
        conn.release();
        if (dataErr) {
          console.error("Data error:", dataErr);
          return res.status(500).json({ error: "Fetch failed" });
        }

        res.status(200).json({
          success:    true,
          data:       results,
          totalPages,
          total,
          pagination: { total, totalPages, currentPage: pageNum, limit: limitNum },
        });
      });
    });
  });
});

