app.delete("/delete-notification/:id/:campus_id", (req, res) => {
  const { id, campus_id } = req.params;

  // Pehle file ka path lao, phir delete karo
  connection.getConnection((err, conn) => {
    if (err) return res.status(500).json({ error: "DB connection error" });
    conn.query(`SELECT notification_file FROM notifications WHERE id = ? AND campus_id = ?`, [id, campus_id], (err, results) => {
      if (err) { conn.release(); return res.status(500).json({ error: "Fetch failed" }); }

      // File system se bhi delete karo
      if (results[0]?.notification_file) {
        const filePath = `uploads/${results[0].notification_file}`;
        if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
      }

      conn.query(`DELETE FROM notifications WHERE id = ? AND campus_id = ?`, [id, campus_id], (error) => {
        conn.release();
        if (error) { console.error(error); return res.status(500).json({ error: "Delete failed" }); }
        res.json({ success: true, message: "Deleted successfully" });
      });
    });
  });
});

