app.get("/get-homework/:id_get/:campus_id/:session_id", (req, res) => {
  const id_get = req.params.id_get;
  const campus_id = req.params.campus_id;
  const session_id = req.params.session_id;

  connection.getConnection((err, connection) => {
    if (err) {
      console.error("Error:", err);
      res.status(500).json({ error: "Error fetching" });
      return;
    }

    const sql = `
    SELECT hw.*, 
        hw.assign_subject_id as assign_subject_id,  -- ✅ This is the subject_id
        hw.assing_subjects_class_teacher_id,        -- ✅ Keep this too
        c.class as class_name, 
        s.section_name, 
        sub.subjects,
        hw.shift,
        hw.class_id,
        hw.section_id
      FROM homework hw
      JOIN subjects sub ON hw.assign_subject_id = sub.id
      JOIN classes c ON hw.class_id = c.id
      JOIN sections s ON hw.section_id = s.id
      WHERE hw.campus_id = ? AND hw.session_id = ? AND hw.id = ?`;

    const values = [campus_id, session_id, id_get];

    connection.query(sql, values, (error, results) => {
      connection.release(); // Release the connection

      if (error) {
        console.error("Error executing SQL query: ", error);
        res.status(500).json({ error: "Internal server error" });
      } else {
        res.json({
          results,
        });
      }
    });
  });
});

