app.get("/homework-list", (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 10;
  const search = req.query.search || "";
  const search_date = req.query.search_date || "";
  const offset = (page - 1) * limit;
  const { campus_id, session_id, teacher_assignments } = req.query;
  const shift = req.query.shift || "";
  const class_id = req.query.class_id || "";
  const section_id = req.query.section_id || "";
  
  connection.getConnection((err, connection) => {
    if (err) {
      console.error("Error:", err);
      res.status(500).json({ error: "Error fetching homework list" });
      return;
    }
    
    let sql = `
      SELECT hw.*, 
        c.class as class_name, 
        s.section_name, 
        sub.subjects
      FROM homework hw
      JOIN subjects sub ON hw.assign_subject_id = sub.id
      JOIN classes c ON hw.class_id = c.id
      JOIN sections s ON hw.section_id = s.id
      WHERE hw.campus_id = ? AND hw.session_id = ?
    `;
    
    let countSql = `
      SELECT COUNT(*) as total
      FROM homework hw
      WHERE hw.campus_id = ? AND hw.session_id = ?
    `;
    
    let params = [campus_id, session_id];
    let countParams = [campus_id, session_id];
    
    // ✅ Build dynamic WHERE clause based on teacher assignments
    if (teacher_assignments) {
      try {
        const assignments = JSON.parse(teacher_assignments);
        
        if (assignments && assignments.length > 0) {
          // Build OR conditions for each assignment
          const conditions = assignments.map(() => 
            `(hw.assign_subject_id = ? AND hw.class_id = ? AND hw.section_id = ? AND hw.shift = ?)`
          ).join(' OR ');
          
          sql += ` AND (${conditions})`;
          countSql += ` AND (${conditions})`;
          
          // Add parameters for each assignment
          assignments.forEach(assignment => {
            params.push(
              assignment.subject_id,
              assignment.class_id,
              assignment.section_id,
              assignment.shift
            );
            countParams.push(
              assignment.subject_id,
              assignment.class_id,
              assignment.section_id,
              assignment.shift
            );
          });
        }
      } catch (error) {
        console.error("Error parsing teacher_assignments:", error);
        connection.release();
        res.status(400).json({ error: "Invalid teacher assignments data" });
        return;
      }
    }
    
    if (shift) {
      sql += ` AND hw.shift = ?`;
      countSql += ` AND hw.shift = ?`;
      params.push(shift);
      countParams.push(shift);
    }
    
    if (class_id) {
      sql += ` AND hw.class_id = ?`;
      countSql += ` AND hw.class_id = ?`;
      params.push(class_id);
      countParams.push(class_id);
    }
    
    if (section_id) {
      sql += ` AND hw.section_id = ?`;
      countSql += ` AND hw.section_id = ?`;
      params.push(section_id);
      countParams.push(section_id);
    }
    
    if (search) {
      sql += ` AND (sub.subjects LIKE ? OR c.class LIKE ? OR s.section_name LIKE ? OR hw.description LIKE ?)`;
      countSql += ` AND EXISTS (
        SELECT 1 FROM homework hw2
        JOIN subjects sub ON hw2.assign_subject_id = sub.id
        JOIN classes c ON hw2.class_id = c.id
        JOIN sections s ON hw2.section_id = s.id
        WHERE hw2.id = hw.id
        AND (sub.subjects LIKE ? OR c.class LIKE ? OR s.section_name LIKE ? OR hw2.description LIKE ?)
      )`;
      
      const searchTerm = `%${search}%`;
      params.push(searchTerm, searchTerm, searchTerm, searchTerm);
      countParams.push(searchTerm, searchTerm, searchTerm, searchTerm);
    }
    
    if (search_date) {
      sql += ` AND DATE(hw.home_work_date) = ?`;
      countSql += ` AND DATE(hw.home_work_date) = ?`;
      params.push(search_date);
      countParams.push(search_date);
    }
    
    sql += ` ORDER BY hw.id DESC LIMIT ? OFFSET ?`;
    params.push(limit, offset);
    
    connection.query(sql, params, (error, results) => {
      if (error) {
        console.error("Error executing SQL query: ", error);
        res.status(500).json({ error: "Internal server error" });
        connection.release();
        return;
      }
      
      connection.query(countSql, countParams, (countError, countResult) => {
        connection.release();
        
        if (countError) {
          console.error("Error executing count SQL query: ", countError);
          res.status(500).json({ error: "Internal server error" });
          return;
        }
        
        const total = countResult[0].total;
        const totalPages = Math.ceil(total / limit);
        
        res.json({
          success: true,
          data: results,
          total: total,
          page: page,
          totalPages: totalPages
        });
      });
    });
  });
});


// Route to fetch bank notes list
app.get("/bank-notes-list", async (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 5;
  const offset = (page - 1) * limit;
  const search_data = req.query.search;
  const campus_id = req.query.campus_id;

  try {
    let sql = `SELECT id, note_title, note_description, status, session_id, campus_id, user_id, created_at, updated_at 
               FROM bank_notes WHERE campus_id = ?`;
    let countSql = `SELECT COUNT(*) AS total FROM bank_notes`;

    const params = [];

    if (search_data) {
      sql += ` AND note_title LIKE ? OR note_description LIKE ?`;
      countSql += ` WHERE note_title LIKE ? OR note_description LIKE ?`;
      params.push(`%${search_data}%`, `%${search_data}%`);
    }

    sql += ` LIMIT ? OFFSET ?`;
    params.push(campus_id, limit, offset);

    const [dataResults, countResult] = await Promise.all([
      connection.query(sql, params),
      connection.query(countSql, params.slice(0, params.length - 2)), // Count query does not need limit and offset
    ]);

    const total = countResult[0].total;
    const totalPages = Math.ceil(total / limit);

    res.json({
      total,
      currentPage: page,
      totalPages,
      results: dataResults,
    });
  } catch (error) {
    console.error("Error fetching bank notes:", error);
    res.status(500).json({ error: "Internal server error" });
  }
});

