app.get("/attendance-status-count", (req, res) => {
  const { from_month, to_month, campus_id, session_id } = req.query;

  if (!from_month || !to_month || !campus_id || !session_id) {
    return res.status(400).json({ error: "Missing required parameters" });
  }

  connection.getConnection((err, connection) => {
    if (err) {
      console.error("Error:", err);
      return res.status(500).json({ error: "Error connecting to the database" });
    }

    // Query: Get status count for each employee between from_month and to_month
    const sqlStatusCount = `
      SELECT 
        e.id as employee_id,
        e.full_name,
        ep.employee_post,
        SUM(CASE WHEN sea.status = 'present' THEN 1 ELSE 0 END) as present_count,
        SUM(CASE WHEN sea.status = 'casual_leave' THEN 1 ELSE 0 END) as casual_leave_count,
        SUM(CASE WHEN sea.status = 'earned_leave' THEN 1 ELSE 0 END) as earned_leave_count,
        SUM(CASE WHEN sea.status = 'maternity_leave' THEN 1 ELSE 0 END) as maternity_leave_count,
        SUM(CASE WHEN sea.status = 'ex_pakistan_leave' THEN 1 ELSE 0 END) as ex_pakistan_leave_count,
        SUM(CASE WHEN sea.status = 'holiday' THEN 1 ELSE 0 END) as holiday_count,
        SUM(CASE WHEN sea.status = 'lwp' THEN 1 ELSE 0 END) as lwp_count,
        COUNT(*) as total_days
      FROM school_employee_attendance sea
      JOIN school_employees e ON sea.employee_id = e.id
      LEFT JOIN employee_posts ep ON e.employee_post_id = ep.id
      WHERE DATE_FORMAT(sea.date, '%Y-%m') BETWEEN ? AND ?
        AND sea.campus_id = ?
      GROUP BY e.id, e.full_name, ep.employee_post
      ORDER BY e.full_name
    `;


    // AND sea.session_id = ?

    connection.query(
      sqlStatusCount,
         [from_month, to_month, campus_id],
      // [from_month, to_month, campus_id, session_id],
      (err, results) => {
        connection.release();

        if (err) {
          console.error("Error fetching status count:", err);
          return res.status(500).json({ error: "Error fetching status count data" });
        }

        res.json({
          success: true,
          results: results,
          from_month: from_month,
          to_month: to_month
        });
      }
    );
  });
});


app.get("/employee-attendance/:date/:campus_id/:session_id", (req, res) => {
  const { date, campus_id, session_id } = req.params;

  connection.getConnection((err, connection) => {
    if (err) {
      console.error("Error:", err);
      return res.status(500).json({ error: "Error connecting to the database" });
    }

    // Query 1: Get all employees
    const sqlEmployees = `
      SELECT 
        e.id, 
        e.full_name, 
        ep.employee_post, 
        ps.pay_scale, 
        ps.job_type
      FROM school_employees e
      LEFT JOIN employee_posts ep ON e.employee_post_id = ep.id
      LEFT JOIN pay_scale ps ON e.pay_scale_id = ps.id
      WHERE e.campus_id = ? 
        AND (e.resign_retire_terminate_date IS NULL OR e.resign_retire_terminate_date = ''
             OR e.resign_retire_terminate_date >= ?)
    `;

    // Query 2: Get attendance for selected date
    const sqlAttendance = `
      SELECT * FROM school_employee_attendance 
      WHERE date = ? AND campus_id = ?
    `;

    // Execute both queries
    Promise.all([
      new Promise((resolve, reject) => {
        connection.query(sqlEmployees, [campus_id, date], (error, results) => {
          if (error) reject(error);
          else resolve(results);
        });
      }),
      new Promise((resolve, reject) => {
        connection.query(sqlAttendance, [date, campus_id], (error, results) => {
          if (error) reject(error);
          else resolve(results);
        });
      })
    ])
      .then(([employees, attendance]) => {
        connection.release();
        res.json({ 
          employees, 
          attendance
        });
      })
      .catch((error) => {
        connection.release();
        console.error("Error executing queries:", error);
        res.status(500).json({ error: "Internal server error" });
      });
  });
});


app.post("/school-employee-attendance", (req, res) => {
  const { date, attendanceData } = req.body;

  connection.getConnection((err, connection) => {
    if (err) {
      console.error("Error:", err);
      res.status(500).json({ error: "Error connecting to the database" });
      return;
    }

    // First, fetch existing attendance data for the date
    const fetchSql =
      "SELECT employee_id FROM school_employee_attendance WHERE date = ?";
    connection.query(fetchSql, [date], (fetchError, fetchResults) => {
      if (fetchError) {
        connection.release();
        console.error("Error fetching existing attendance:", fetchError);
        res.status(500).json({ error: "Internal server error" });
        return;
      }

      // Extract existing employee IDs
      const existingEmployeeIds = fetchResults.map(
        (result) => result.employee_id
      );

      // Separate data into updates and inserts
      const updateData = [];
      const insertData = [];

      attendanceData.forEach((item) => {
        if (existingEmployeeIds.includes(item.employee_id)) {
          updateData.push([item.status, item.remarks, item.employee_id, date]);
        } else {
          insertData.push([item.employee_id, date, item.status, item.remarks]);
        }
      });

      // Perform updates if any
      if (updateData.length > 0) {
        const updateSql =
          "UPDATE school_employee_attendance SET status = ?, remarks = ? WHERE employee_id = ? AND date = ?";
        updateData.forEach((data) => {
          connection.query(updateSql, data, (updateError) => {
            if (updateError) {
              connection.release();
              console.error("Error updating attendance data:", updateError);
              res.status(500).json({ error: "Internal server error" });
              return;
            }
          });
        });
      }

      // Perform inserts if any
      if (insertData.length > 0) {
        const insertSql =
          "INSERT INTO attendance (employee_id, date, status, remarks) VALUES ?";
        connection.query(insertSql, [insertData], (insertError) => {
          if (insertError) {
            connection.release();
            console.error("Error inserting attendance data:", insertError);
            res.status(500).json({ error: "Internal server error" });
            return;
          }
        });
      }

      // Ensure the connection is released only once after all operations are complete
      connection.release();
      res.json({ message: "Attendance data saved/updated successfully!" });
    });
  });
});

