io.on('connection', (socket) => {
    console.log('🔌 Dashboard connected:', socket.id);
    
    socket.emit('connected', { 
        message: 'Connected to attendance server',
        timestamp: new Date().toISOString()
    });

    socket.on('disconnect', () => {
        console.log('🔌 Dashboard disconnected:', socket.id);
    });

    // Handle refresh request from dashboard
    socket.on('request-refresh', async (data) => {
        console.log('🔄 Refresh requested');
        const { campus_id, session_id, date } = data;
        const attendanceData = await fetchAttendanceData(campus_id, session_id, date);
        socket.emit('attendance-update', attendanceData);
    });
});




