const fetchAttendanceData = async (campus_id, session_id, date) => {
    return new Promise((resolve, reject) => {
        connection.getConnection((err, conn) => {
            if (err) {
                reject(err);
                return;
            }

            const today = date || new Date().toISOString().split('T')[0];

            const sqlTotal = `
                SELECT COUNT(*) as total
                FROM school_employees 
                WHERE campus_id = ? 
                    AND (resign_retire_terminate_date IS NULL 
                         OR resign_retire_terminate_date = ''
                         OR resign_retire_terminate_date >= ?)
            `;

            const sqlAttendance = `
                SELECT 
                    sea.id,
                    sea.employee_id,
                    sea.date,
                    sea.status,
                    sea.remarks,
                    sea.first_punch,
                    sea.last_punch,
                    sea.total_punches,
                    sea.working_hours,
                    sea.created_at,
                    sea.updated_at,
                    e.full_name,
                    ep.employee_post,
                    ps.pay_scale,
                    ps.job_type
                FROM school_employee_attendance sea
                INNER JOIN school_employees e ON sea.employee_id = e.id
                LEFT JOIN employee_posts ep ON e.employee_post_id = ep.id
                LEFT JOIN pay_scale ps ON e.pay_scale_id = ps.id
                WHERE sea.date = ? 
                    AND sea.campus_id = ? 
                ORDER BY sea.updated_at DESC
            `;

            Promise.all([
                new Promise((res, rej) => {
                    conn.query(sqlTotal, [campus_id, today], (error, results) => {
                        if (error) rej(error);
                        else res(results[0]?.total || 0);
                    });
                }),
                new Promise((res, rej) => {
                    conn.query(sqlAttendance, [today, campus_id], (error, results) => {
                        if (error) rej(error);
                        else res(results);
                    });
                })
            ])
            .then(([totalEmployees, attendance]) => {
                conn.release();
                console.log(`✅ Fetched: ${attendance.length} records, Total: ${totalEmployees}`);
                resolve({
                    totalEmployees,
                    attendance,
                    campus_id,
                    timestamp: new Date().toISOString()
                });
            })
            .catch((error) => {
                conn.release();
                reject(error);
            });
        });
    });
};

