app.post('/api/attendance/notify', async (req, res) => {
    try {
        const { employee_id, campus_id, session_id, date } = req.body;

        console.log('📢 Notification:', { employee_id, campus_id, date });

        const attendanceData = await fetchAttendanceData(
            campus_id, 
            session_id || 1,
            date || new Date().toISOString().split('T')[0]
        );

        io.emit('attendance-update', attendanceData);
        
        const clientCount = io.engine.clientsCount;
        console.log(`✅ Sent to ${clientCount} client(s)`);

        res.json({ 
            success: true, 
            connectedClients: clientCount,
            records: attendanceData.attendance.length
        });

    } catch (error) {
        console.error('❌ Error:', error);
        res.status(500).json({ 
            success: false, 
            error: error.message
        });
    }
});

